import{_ as a,o as t,c as n,a2 as o}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Why Sovereign?","description":"Understand the practical reasons for running shared apps on a Sovereign instance.","frontmatter":{"title":"Why Sovereign?","description":"Understand the practical reasons for running shared apps on a Sovereign instance.","aside":false},"headers":[],"relativePath":"product/why-sovereign.md","filePath":"product/why-sovereign.md"}'),r={name:"product/why-sovereign.md"};function s(i,e,p,c,d,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="why-sovereign" tabindex="-1">Why Sovereign? <a class="header-anchor" href="#why-sovereign" aria-label="Permalink to &quot;Why Sovereign?&quot;">​</a></h1><p>Groups often rely on separate hosted services for every shared task. Each tool brings another account, another policy, another data boundary, and another integration to maintain. Building a custom alternative usually means rebuilding the same platform foundations before work on the actual problem can begin.</p><p>Sovereign provides a common runtime for those apps.</p><h2 id="one-environment-for-shared-tools" tabindex="-1">One environment for shared tools <a class="header-anchor" href="#one-environment-for-shared-tools" aria-label="Permalink to &quot;One environment for shared tools&quot;">​</a></h2><p>Users enter one workspace and open the apps their operator has made available. Identity, navigation, account controls, and platform behavior remain consistent across those apps.</p><h2 id="infrastructure-chosen-by-the-group" tabindex="-1">Infrastructure chosen by the group <a class="header-anchor" href="#infrastructure-chosen-by-the-group" aria-label="Permalink to &quot;Infrastructure chosen by the group&quot;">​</a></h2><p>An operator can run Sovereign on infrastructure appropriate for the group and choose its access, retention, backup, and upgrade policies. That creates control, not automatic trust: the users still depend on the operator to run the instance responsibly.</p><h2 id="a-foundation-for-custom-needs" tabindex="-1">A foundation for custom needs <a class="header-anchor" href="#a-foundation-for-custom-needs" aria-label="Permalink to &quot;A foundation for custom needs&quot;">​</a></h2><p>When an existing app does not fit, a developer can build a Sovereign app around the missing workflow. The runtime provides reusable contracts for identity, app-scoped data, platform UI, and other capabilities, reducing the platform work that would otherwise be repeated for each custom service.</p><h2 id="open-and-inspectable" tabindex="-1">Open and inspectable <a class="header-anchor" href="#open-and-inspectable" aria-label="Permalink to &quot;Open and inspectable&quot;">​</a></h2><p>Sovereign is licensed under AGPL-3.0. Operators and developers can inspect the source, run it themselves, adapt it, and contribute improvements upstream.</p><h2 id="a-consistent-app-contract" tabindex="-1">A consistent app contract <a class="header-anchor" href="#a-consistent-app-contract" aria-label="Permalink to &quot;A consistent app contract&quot;">​</a></h2><p>User-facing apps are delivered as plugins. The plugin manifest and SDK define how an app participates in the workspace and accesses approved platform capabilities. This keeps the runtime boundary explicit instead of treating apps as unrestricted runtime code.</p><p><a href="./how-it-works.html">See how Sovereign works</a></p>',14)])])}const f=a(r,[["render",s]]);export{u as __pageData,f as default};
